      if (Math.abs(o1) <= 1e-12 && onSeg(a.x, a.y, b.x, b.y, c.x, c.y)) return true;
      if (Math.abs(o2) <= 1e-12 && onSeg(a.x, a.y, b.x, b.y, d.x, d.y)) return true;
